#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_global_int32_base_atomics : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

__kernel void pgain_kernel(
    __global Point_Struct* p,
    __global float* coord,
    __global float* work_mem,
    __global int* center_table,
    __global char* switch_membership,
    __local float* local_coord,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    int gid = get_global_id(0);
    if (gid >= num) return;

    // Load coordinates of point gid into local memory
    for (int i = get_local_id(0); i < dim; i += get_local_size(0)) {
        local_coord[i] = coord[dim * gid + i];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute distance from point gid to point x
    float x_cost = 0.0f;
    for (int i = 0; i < dim; i++) {
        float diff = local_coord[i] - coord[dim * x + i];
        x_cost += diff * diff;
    }
    x_cost *= p[gid].weight;

    float current_cost = p[gid].cost;

    if (x_cost < current_cost) {
        switch_membership[gid] = 1;
        // No atomic add here; accumulation done on host
    } else {
        int assign = p[gid].assign;
        // Atomic add on float emulated via atomic_cmpxchg on unsigned int
        __global unsigned int* addr = (__global unsigned int*)(&work_mem[center_table[assign] + gid * (K + 1)]);
        union {
            unsigned int intVal;
            float floatVal;
        } oldVal, newVal;

        oldVal.floatVal = as_float(atomic_load_explicit(addr, memory_order_relaxed));
        do {
            newVal.floatVal = oldVal.floatVal + (current_cost - x_cost);
            unsigned int prev = atomic_cmpxchg(addr, oldVal.intVal, as_uint(newVal.floatVal));
            if (prev == oldVal.intVal) break;
            oldVal.intVal = prev;
        } while (1);

        switch_membership[gid] = 0;
    }
}

